const intent = $json.intent || '';
const params = $json.intentParams || {};
const GOOGLE_API_KEY = $env.GOOGLE_API_KEY || '';

if (!GOOGLE_API_KEY) {
  return [{ json: { ...$json, responseText: '⚠️ GOOGLE_API_KEY not configured.', success: false } }];
}

let endpoint, body, method = 'GET';
if (intent === 'slides_create') {
  endpoint = 'https://slides.googleapis.com/v1/presentations';
  method = 'POST';
  body = { title: params.title || 'Untitled Presentation' };
} else {
  return [{ json: { ...$json, responseText: '❓ Unknown Slides intent: ' + intent, success: false } }];
}

return [{ json: { ...$json, apiEndpoint: endpoint, apiBody: body, apiMethod: method } }];

if ($json.presentationId) {
  const url = `https://docs.google.com/presentation/d/${$json.presentationId}/edit`;
  return [{ json: { ...$input.item.json, responseText: `🏄 Presentation created!

<b>${$json.title}</b>

🔗 ${url}`, success: true } }];
}
return [{ json: { ...$input.item.json, responseText: `🏄 Slides operation completed.`, success: true } }];
